import { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [isLogin, setIsLogin] = useState(false);
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [courses, setCourses] = useState([]);
  const [enrolled, setEnrolled] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [progress, setProgress] = useState({});

  const handleAuth = async () => {
    const url = isRegister
      ? "http://localhost:5000/register"
      : "http://localhost:5000/login";

    await axios.post(url, { email, password });
    setIsLogin(true);
  };

  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then((res) => {
        setCourses(res.data);
      });

      axios.get("http://localhost:5000/enrolled").then((res) => {
        setEnrolled(res.data);
      });
    }
  }, [isLogin]);

  const handleEnroll = async (course) => {
    await axios.post("http://localhost:5000/enroll", { course });

    const res = await axios.get("http://localhost:5000/enrolled");
    setEnrolled(res.data);
  };

  const markComplete = (id) => {
    setProgress({ ...progress, [id]: 100 });
  };

  // 🎓 CERTIFICATE DOWNLOAD
  const downloadCertificate = (course) => {
    const blob = new Blob(
      [`Certificate of Completion\n\nThis certifies completion of ${course.title}`],
      { type: "text/plain" }
    );

    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `${course.title}_certificate.txt`;
    link.click();
  };

  // 🔐 LOGIN
  if (!isLogin) {
    return (
      <div style={styles.auth}>
        <div style={styles.box}>
          <h2>{isRegister ? "Register" : "Login"}</h2>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />
          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.btn} onClick={handleAuth}>
            {isRegister ? "Register" : "Login"}
          </button>

          <p onClick={() => setIsRegister(!isRegister)} style={{ cursor: "pointer" }}>
            {isRegister ? "Login here" : "Create account"}
          </p>
        </div>
      </div>
    );
  }

  // 🎥 VIDEO PAGE
  if (selectedCourse) {
    const percent = progress[selectedCourse.id] || 0;

    return (
      <div style={{ textAlign: "center", padding: "40px" }}>
        <h2>{selectedCourse.title}</h2>

        <iframe
          width="800"
          height="400"
          src={selectedCourse.video}
          title="video"
        />

        <br /><br />

        <button onClick={() => markComplete(selectedCourse.id)}>
          Mark Complete ✅
        </button>

        <h3>Progress: {percent}%</h3>

        {percent === 100 && (
          <button onClick={() => downloadCertificate(selectedCourse)}>
            🎓 Download Certificate
          </button>
        )}

        <br /><br />

        <button onClick={() => setSelectedCourse(null)}>⬅ Back</button>
      </div>
    );
  }

  // 📊 DASHBOARD
  return (
    <div style={styles.main}>
      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h3>My Courses</h3>

        {enrolled.map((c) => (
          <div key={c.id} onClick={() => setSelectedCourse(c)} style={styles.item}>
            {c.title}
          </div>
        ))}
      </div>

      {/* CONTENT */}
      <div style={styles.content}>
        <h1>Explore Courses</h1>

        <div style={styles.grid}>
          {courses.map((course) => {
            const isEnrolled = enrolled.find((c) => c.id === course.id);

            return (
              <div key={course.id} style={styles.card}>
                <img src={course.image} style={styles.image} alt="course" />

                <h3>{course.title}</h3>
                <p>{course.description}</p>

                {!isEnrolled ? (
                  <button onClick={() => handleEnroll(course)}>Enroll</button>
                ) : (
                  <button onClick={() => setSelectedCourse(course)}>
                    Watch 🎥
                  </button>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  auth: { display: "flex", justifyContent: "center", alignItems: "center", height: "100vh" },
  box: { padding: "30px", background: "white", borderRadius: "10px" },
  input: { display: "block", margin: "10px", padding: "10px" },
  btn: { padding: "10px 20px" },
  main: { display: "flex" },
  sidebar: { width: "200px", background: "#111", color: "white", padding: "20px" },
  item: { marginTop: "10px", cursor: "pointer" },
  content: { padding: "20px", flex: 1 },
  grid: { display: "flex", gap: "20px" },
  card: { padding: "20px", background: "white", borderRadius: "10px" },
  image: {
  width: "100%",
  height: "150px",
  objectFit: "contain",   // 👈 important for logos
  background: "#f4f4f4",
  padding: "10px",
},
};

export default App;
